=<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Workflow Error Notification</title>
    <style>
        /* Base Styles */
        body { margin: 0; padding: 0; background-color: #f4f7f6; font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; -webkit-font-smoothing: antialiased; }

        /* Layout */
        .wrapper { width: 100%; background-color: #f4f7f6; padding-bottom: 40px; }
        .main-content { background-color: #ffffff; margin: 0 auto; width: 100%; max-width: 600px; border-radius: 8px; overflow: hidden; box-shadow: 0 4px 6px rgba(0,0,0,0.05); }

        /* Header */
        .header { background-color: #1e293b; padding: 30px; text-align: center; border-bottom: 4px solid #ef4444; }
        .header h1 { color: #ffffff; margin: 0; font-size: 24px; font-weight: 600; }
        .header p { color: #94a3b8; margin: 5px 0 0 0; font-size: 14px; text-transform: uppercase; letter-spacing: 1px; }

        /* Content */
        .content-section { padding: 40px; }
        .intro-text { color: #334155; font-size: 16px; line-height: 1.6; margin-bottom: 30px; }

        /* Data Layout (Div based) */
        .data-container { width: 100%; margin-bottom: 25px; border: 1px solid #e2e8f0; border-radius: 6px; overflow: hidden; }
        .data-header { background-color: #f8fafc; padding: 12px 20px; border-bottom: 1px solid #e2e8f0; }
        .data-header h3 { margin: 0; font-size: 14px; color: #475569; text-transform: uppercase; letter-spacing: 0.5px; font-weight: 700; }

        .data-row { 
            display: flex; 
            padding: 12px 20px; 
            border-bottom: 1px solid #f1f5f9; 
            font-size: 14px; 
        }
        .data-row:last-child { border-bottom: none; }
        .label { color: #64748b; font-weight: 600; width: 35%; flex-shrink: 0; }
        .value { color: #0f172a; flex-grow: 1; word-break: break-word; }

        /* Error Specifics */
        .error-block { background-color: #fef2f2; border: 1px solid #fecaca; border-radius: 6px; padding: 20px; }
        .error-title { color: #991b1b; font-weight: 700; margin-bottom: 15px; font-size: 16px; display: flex; align-items: center; }

        .error-info-row { display: flex; margin-bottom: 8px; font-size: 13px; }
        .error-label { color: #7f1d1d; font-weight: 600; width: 100px; flex-shrink: 0; }
        .error-value { color: #111827; flex-grow: 1; }

        .code-block { background-color: #fff; border: 1px solid #fee2e2; padding: 15px; border-radius: 4px; font-family: 'Courier New', monospace; font-size: 12px; color: #dc2626; overflow-x: auto; white-space: pre-wrap; word-break: break-all; margin-top: 8px; }

        /* Footer */
        .footer { background-color: #f1f5f9; padding: 30px; text-align: center; color: #94a3b8; font-size: 12px; }

        /* Link styles */
        a { color: #2563eb; text-decoration: none; font-weight: 600; }
        a:hover { text-decoration: underline; }
    </style>
</head>
<body>

    <div class="wrapper">
        <br>
        <div class="main-content">

            <!-- Header -->
            <div class="header">
                <h1>⚠️ Workflow Execution Failed</h1>
                <p>System Alert Notification</p>
            </div>

            <div class="content-section">
                <!-- Intro -->
                <div class="intro-text">
                    An error occurred during the execution of an automated workflow. Please review the diagnostic details below.
                </div>

                <!-- Workflow Details Card -->
                <div class="data-container">
                    <div class="data-header">
                        <h3>Workflow Information</h3>
                    </div>
                    <!-- Row 1 -->
                    <div class="data-row">
                        <div class="label">Workflow Name</div>
                        <div class="value">{{$node["Error Trigger"].json["workflow"]["name"]}}</div>
                    </div>
                    <!-- Row 2 -->
                    <div class="data-row">
                        <div class="label">Workflow ID</div>
                        <div class="value">{{$node["Error Trigger"].json["workflow"]["id"]}}</div>
                    </div>
                    <!-- Row 3 -->
                    <div class="data-row">
                        <div class="label">Execution ID</div>
                        <div class="value">{{$node["Error Trigger"].json["execution"]["id"]}}</div>
                    </div>
                    <!-- Row 4 -->
                    <div class="data-row">
                        <div class="label">Timestamp</div>
                        <div class="value">{{$now.toISO()}}</div>
                    </div>
                    <!-- Row 5 -->
                    <div class="data-row">
                        <div class="label">Retry Count</div>
                        <div class="value">{{$node["Error Trigger"].json["execution"]["retryOf"] || "0"}}</div>
                    </div>
                    <!-- Row 6 -->
                    <div class="data-row">
                        <div class="label">Action</div>
                        <div class="value"><a href="{{$node["Error Trigger"].json["execution"]["url"]}}">View Execution Log &rarr;</a></div>
                    </div>
                </div>

                <!-- Error Details Card -->
                <div class="error-block">
                    <div class="error-title">
                        🚫 Critical Error
                    </div>

                    <div class="error-info-row">
                        <div class="error-label">Failed Node:</div>
                        <div class="error-value">{{$node["Error Trigger"].json.execution.lastNodeExecuted}}</div>
                    </div>

                    <div class="error-info-row">
                        <div class="error-label">Message:</div>
                        <div class="error-value">{{$node["Error Trigger"].json.execution.error.message}}</div>
                    </div>

                    <div style="font-size: 12px; font-weight: 600; color: #7f1d1d; margin-top: 15px; margin-bottom: 8px; text-transform: uppercase;">Stack Trace</div>
                    <div class="code-block">
{{$node["Error Trigger"].json.execution.error.stack}}
                    </div>
                </div>

            </div>

            <!-- Footer -->
            <div class="footer">
                Elite Security Specialists - Automated Workflow System<br>
                This is a system generated message.
            </div>

        </div>
    </div>

</body>
</html>
